// Parse & Clean Articles — regex XML parser, no external libs
const feeds = [
  { node: "Fetch FT RSS",            source: "Financial Times" },
  { node: "Fetch Reuters RSS",       source: "Reuters" },
  { node: "Fetch Seeking Alpha RSS", source: "Seeking Alpha" },
  { node: "Fetch CNBC RSS",          source: "CNBC" },
  { node: "Fetch Yahoo Finance RSS", source: "Yahoo Finance" }
];

function stripHtml(s) {
  return String(s || "")
    .replace(/<!\[CDATA\[([\s\S]*?)\]\]>/g, "$1")
    .replace(/<[^>]*>/g, " ")
    .replace(/&nbsp;/gi, " ")
    .replace(/&amp;/gi, "&")
    .replace(/&lt;/gi, "<")
    .replace(/&gt;/gi, ">")
    .replace(/&quot;/gi, '"')
    .replace(/&#39;/gi, "'")
    .replace(/&[a-z0-9#]+;/gi, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function unwrapCdata(s) {
  const m = String(s || "").match(/<!\[CDATA\[([\s\S]*?)\]\]>/);
  return m ? m[1] : s;
}

function tagValue(block, tag) {
  const re = new RegExp("<" + tag + "[^>]*>([\\s\\S]*?)<\\/" + tag + ">", "i");
  const m = block.match(re);
  return m ? unwrapCdata(m[1]).trim() : "";
}

function toIso(d) {
  if (!d) return null;
  const t = Date.parse(d);
  return isNaN(t) ? null : new Date(t).toISOString();
}

function rawText(nodeName) {
  let item;
  try { item = $(nodeName).first(); } catch (e) { return ""; }
  if (!item || !item.json) return "";
  const j = item.json;
  // n8n HTTP Request (responseFormat: text) stores body under .data; guard others
  return j.data || j.body || j.response || (typeof j === "string" ? j : "") || "";
}

const articles = [];

for (const feed of feeds) {
  const xml = rawText(feed.node);
  if (!xml) continue;
  const items = xml.match(/<item[\s\S]*?<\/item>/gi)
            || xml.match(/<entry[\s\S]*?<\/entry>/gi)
            || [];
  for (const block of items) {
    const headline = stripHtml(tagValue(block, "title"));
    let link = tagValue(block, "link");
    if (!link) {
      // Atom feeds use <link href="..."/>
      const m = block.match(/<link[^>]*href=["']([^"']+)["']/i);
      link = m ? m[1] : "";
    }
    const article_url = (link || "").trim();
    const pub = tagValue(block, "pubDate") || tagValue(block, "published") || tagValue(block, "updated");
    let summary = stripHtml(tagValue(block, "description") || tagValue(block, "summary") || tagValue(block, "content"));
    if (summary.length > 500) summary = summary.slice(0, 500);

    if (!headline || !article_url) continue;

    articles.push({
      article_url,
      headline,
      summary,
      source: feed.source,
      published_at: toIso(pub) || new Date().toISOString()
    });
  }
}

const watchlist = $('Fetch Watchlist').first().json.watchlist;

return [{ json: { articles, watchlist } }];

// Deduplicate Against Supabase — filter out URLs seen in last 7 days
const articles = $json.articles || [];
const watchlist = $json.watchlist || [];

const SUPABASE_URL = $env.SUPABASE_URL;
const SUPABASE_KEY = $env.SUPABASE_KEY;

const sevenDaysAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000).toISOString();

let knownUrls = new Set();
try {
  const url = SUPABASE_URL +
    "/rest/v1/media_narratives_raw?select=article_url&created_at=gte." +
    encodeURIComponent(sevenDaysAgo);
  const resp = await this.helpers.httpRequest({
    method: "GET",
    url,
    headers: {
      apikey: SUPABASE_KEY,
      Authorization: "Bearer " + SUPABASE_KEY,
      "Content-Type": "application/json"
    },
    json: true
  });
  const rows = Array.isArray(resp) ? resp : [];
  knownUrls = new Set(rows.map(r => r.article_url));
} catch (e) {
  // If the read fails, proceed without dedup rather than dropping the run
  console.log("Dedup read failed, continuing without dedup:", e.message);
}

const newArticles = articles.filter(a => !knownUrls.has(a.article_url));
const skippedCount = articles.length - newArticles.length;

if (newArticles.length === 0) {
  return [{ json: { status: "no_new_articles", skipped: skippedCount, newArticles: [], watchlist } }];
}

return [{ json: { newArticles, watchlist, skippedCount } }];

// Aggregate for Claude — same payload feeds all 3 Claude nodes
const newArticles = $json.newArticles || [];
const watchlist = $json.watchlist || [];

return [{
  json: {
    articles: newArticles,
    watchlist,
    batchSize: newArticles.length
  }
}];

