// Signal Assembler — merge 3 Claude outputs by article_url
function genUuid() {
  // RFC4122 v4 without crypto dependency
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function (c) {
    const r = Math.floor(Math.random() * 16);
    const v = c === 'x' ? r : (r & 0x3) | 0x8;
    return v.toString(16);
  });
}

function parseClaude(raw) {
  if (raw == null) return null;
  let text = typeof raw === "string" ? raw : (raw.text || raw.output || raw.response || raw.data || "");
  if (typeof text !== "string") {
    // already structured
    if (Array.isArray(text)) return text;
    if (typeof raw === "object" && Array.isArray(raw)) return raw;
  }
  text = String(text).trim();
  // strip code fences
  text = text.replace(/^\`\`\`(?:json)?/i, "").replace(/\`\`\`$/,"").trim();
  const start = text.indexOf("[");
  const end = text.lastIndexOf("]");
  if (start !== -1 && end !== -1 && end > start) {
    text = text.slice(start, end + 1);
  }
  try {
    return JSON.parse(text);
  } catch (e) {
    console.log("Claude parse failure:", e.message);
    return null;
  }
}

const all = $input.all();

// Each Claude node arrives on its own merge input slot.
function claudeOutputAt(idx) {
  const item = all[idx];
  if (!item || !item.json) return null;
  return item.json;
}

const c1 = parseClaude(claudeOutputAt(0)) || [];
const c2 = parseClaude(claudeOutputAt(1)) || [];
const c3 = parseClaude(claudeOutputAt(2)) || [];

const byUrl = {};
function ensure(url) {
  if (!byUrl[url]) byUrl[url] = { article_url: url };
  return byUrl[url];
}

for (const r of (Array.isArray(c1) ? c1 : [])) {
  if (!r || !r.article_url) continue;
  const o = ensure(r.article_url);
  o.core_claim = r.core_claim;
  o.claim_type = r.claim_type;
}
for (const r of (Array.isArray(c2) ? c2 : [])) {
  if (!r || !r.article_url) continue;
  const o = ensure(r.article_url);
  o.information_age_score = r.information_age_score;
  o.is_recycled = r.is_recycled;
  o.narrative_label = r.narrative_label;
}
for (const r of (Array.isArray(c3) ? c3 : [])) {
  if (!r || !r.article_url) continue;
  const o = ensure(r.article_url);
  o.companies_mentioned = r.companies_mentioned || [];
}

// Source article metadata from the Aggregate node
let sourceArticles = [];
try { sourceArticles = $('Aggregate for Claude').first().json.articles || []; } catch (e) {}
const metaByUrl = {};
for (const a of sourceArticles) metaByUrl[a.article_url] = a;

const runId = genUuid();
const now = new Date().toISOString();
const parseFailed = (c1.length + c2.length + c3.length) === 0;

const records = Object.values(byUrl).map(o => {
  const meta = metaByUrl[o.article_url] || {};
  return {
    article_url: o.article_url,
    headline: meta.headline || null,
    summary: meta.summary || null,
    source: meta.source || null,
    published_at: meta.published_at || null,
    core_claim: o.core_claim || null,
    claim_type: o.claim_type || null,
    information_age_score: typeof o.information_age_score === "number" ? o.information_age_score : null,
    is_recycled: typeof o.is_recycled === "boolean" ? o.is_recycled : null,
    narrative_label: o.narrative_label || null,
    companies_mentioned: o.companies_mentioned || [],
    first_appearance_date: now,
    appearance_count: 1,
    agent_run_id: runId,
    processed_at: now,
    signal_type: parseFailed ? "parse_error" : "ok"
  };
});

return records.map(r => ({ json: r }));

// Build Dashboard HTML — full inline SPA
const rows = $input.all().map(i => i.json).filter(Boolean);

const total = rows.length;
const novel = rows.filter(r => (r.information_age_score || 0) >= 60).length;
const recycled = rows.filter(r => r.is_recycled === true).length;

// most mentioned company
const mentionCounts = {};
for (const r of rows) {
  let cm = r.companies_mentioned;
  if (typeof cm === "string") { try { cm = JSON.parse(cm); } catch (e) { cm = []; } }
  for (const c of (cm || [])) {
    const name = c.companyName || c.ticker;
    if (!name) continue;
    mentionCounts[name] = (mentionCounts[name] || 0) + 1;
  }
}
const mostMentioned = Object.entries(mentionCounts).sort((a,b)=>b[1]-a[1])[0];
const mostMentionedLabel = mostMentioned ? (mostMentioned[0] + " (" + mostMentioned[1] + ")") : "—";

// narrative clusters
const clusters = {};
for (const r of rows) {
  const label = r.narrative_label || "Unlabeled";
  if (!clusters[label]) clusters[label] = { count: 0, sum: 0 };
  clusters[label].count++;
  clusters[label].sum += (r.information_age_score || 0);
}
const clusterRows = Object.entries(clusters)
  .map(([label, c]) => ({ label, count: c.count, avg: Math.round(c.sum / c.count) }))
  .sort((a,b) => b.count - a.count);

const esc = s => String(s == null ? "" : s)
  .replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;").replace(/"/g,"&quot;");

function borderColor(score) {
  if (score >= 80) return "#22c55e";
  if (score >= 40) return "#eab308";
  return "#ef4444";
}

const signalRows = rows
  .slice()
  .sort((a,b) => (b.information_age_score||0) - (a.information_age_score||0))
  .map(r => {
    let cm = r.companies_mentioned;
    if (typeof cm === "string") { try { cm = JSON.parse(cm); } catch(e){ cm=[]; } }
    const companies = (cm||[]).map(c => esc(c.ticker || c.companyName)).join(", ") || "—";
    const score = r.information_age_score == null ? "—" : r.information_age_score;
    const pub = r.published_at ? new Date(r.published_at).toLocaleString() : "—";
    return '<tr style="border-left:5px solid ' + borderColor(r.information_age_score||0) + '">' +
      '<td class="score">' + esc(score) + '</td>' +
      '<td>' + esc(r.narrative_label) + '</td>' +
      '<td><a href="' + esc(r.article_url) + '" target="_blank">' + esc(r.headline) + '</a></td>' +
      '<td>' + esc(r.source) + '</td>' +
      '<td>' + esc(pub) + '</td>' +
      '<td>' + companies + '</td>' +
      '<td>' + esc(r.claim_type) + '</td>' +
      '</tr>';
  }).join("");

const clusterHtml = clusterRows.map(c =>
  '<tr><td>' + esc(c.label) + '</td><td>' + c.count + '</td><td>' + c.avg + '</td></tr>'
).join("");

const companyHtml = Object.entries(mentionCounts).sort((a,b)=>b[1]-a[1]).map(([n,c]) =>
  '<tr><td>' + esc(n) + '</td><td>' + c + '</td></tr>'
).join("");

const html = `<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="utf-8"/>
<meta name="viewport" content="width=device-width, initial-scale=1"/>
<title>Media Narrative Tracker — Mycroft</title>
<style>
  :root{ --bg:#0b0f17; --panel:#141b27; --line:#243044; --txt:#e6edf3; --muted:#8b98ad; --accent:#38bdf8; }
  *{ box-sizing:border-box; }
  body{ margin:0; background:var(--bg); color:var(--txt); font-family:-apple-system,Segoe UI,Roboto,Helvetica,Arial,sans-serif; }
  header{ padding:24px 28px; border-bottom:1px solid var(--line); }
  h1{ margin:0; font-size:22px; } h1 span{ color:var(--accent); }
  .sub{ color:var(--muted); font-size:13px; margin-top:4px; }
  .wrap{ padding:24px 28px; max-width:1400px; margin:0 auto; }
  .cards{ display:grid; grid-template-columns:repeat(4,1fr); gap:16px; margin-bottom:28px; }
  .card{ background:var(--panel); border:1px solid var(--line); border-radius:12px; padding:18px; }
  .card .k{ color:var(--muted); font-size:12px; text-transform:uppercase; letter-spacing:.05em; }
  .card .v{ font-size:28px; font-weight:700; margin-top:6px; }
  h2{ font-size:16px; margin:28px 0 12px; border-left:3px solid var(--accent); padding-left:10px; }
  table{ width:100%; border-collapse:collapse; background:var(--panel); border:1px solid var(--line); border-radius:12px; overflow:hidden; }
  th,td{ text-align:left; padding:10px 12px; font-size:13px; border-bottom:1px solid var(--line); vertical-align:top; }
  th{ color:var(--muted); text-transform:uppercase; font-size:11px; letter-spacing:.05em; cursor:pointer; user-select:none; }
  tr:hover td{ background:#1a2333; }
  td.score{ font-weight:700; font-size:15px; }
  a{ color:var(--accent); text-decoration:none; } a:hover{ text-decoration:underline; }
  .grid2{ display:grid; grid-template-columns:1fr 1fr; gap:24px; }
  footer{ color:var(--muted); font-size:12px; text-align:center; padding:30px 0; border-top:1px solid var(--line); margin-top:32px; }
  @media(max-width:900px){ .cards{ grid-template-columns:repeat(2,1fr);} .grid2{ grid-template-columns:1fr;} }
</style>
</head>
<body>
<header>
  <h1>Media Narrative Tracker — <span>Mycroft</span></h1>
  <div class="sub">Agent 3 · Information-age scoring of financial media · last 48 hours</div>
</header>
<div class="wrap">
  <div class="cards">
    <div class="card"><div class="k">Articles (48h)</div><div class="v">${total}</div></div>
    <div class="card"><div class="k">Novel (score ≥ 60)</div><div class="v" style="color:#22c55e">${novel}</div></div>
    <div class="card"><div class="k">Recycled</div><div class="v" style="color:#ef4444">${recycled}</div></div>
    <div class="card"><div class="k">Most Mentioned</div><div class="v" style="font-size:20px">${mostMentionedLabel}</div></div>
  </div>

  <h2>Signal Table</h2>
  <table id="signalTable">
    <thead><tr>
      <th onclick="sortBy(0,true)">Score</th>
      <th onclick="sortBy(1)">Narrative Label</th>
      <th onclick="sortBy(2)">Headline</th>
      <th onclick="sortBy(3)">Source</th>
      <th onclick="sortBy(4)">Published</th>
      <th onclick="sortBy(5)">Companies</th>
      <th onclick="sortBy(6)">Claim Type</th>
    </tr></thead>
    <tbody>${signalRows || '<tr><td colspan="7" style="color:var(--muted)">No articles in the last 48 hours.</td></tr>'}</tbody>
  </table>

  <div class="grid2">
    <div>
      <h2>Narrative Clusters</h2>
      <table>
        <thead><tr><th>Narrative</th><th>Count</th><th>Avg Age Score</th></tr></thead>
        <tbody>${clusterHtml || '<tr><td colspan="3" style="color:var(--muted)">—</td></tr>'}</tbody>
      </table>
    </div>
    <div>
      <h2>Company Mentions (48h)</h2>
      <table>
        <thead><tr><th>Company</th><th>Mentions</th></tr></thead>
        <tbody>${companyHtml || '<tr><td colspan="2" style="color:var(--muted)">—</td></tr>'}</tbody>
      </table>
    </div>
  </div>

  <footer>Mycroft — Media Narrative Tracker · Agent 3 | n8n + Claude AI + Supabase</footer>
</div>
<script>
  function sortBy(col, numeric){
    const tbody = document.querySelector('#signalTable tbody');
    const rows = Array.from(tbody.querySelectorAll('tr'));
    const dir = tbody.getAttribute('data-dir-' + col) === 'asc' ? 'desc' : 'asc';
    tbody.setAttribute('data-dir-' + col, dir);
    rows.sort((a,b)=>{
      let x = a.children[col] ? a.children[col].innerText : '';
      let y = b.children[col] ? b.children[col].innerText : '';
      if(numeric){ x = parseFloat(x)||0; y = parseFloat(y)||0; return dir==='asc'? x-y : y-x; }
      return dir==='asc' ? x.localeCompare(y) : y.localeCompare(x);
    });
    rows.forEach(r=>tbody.appendChild(r));
  }
</script>
</body>
</html>`;

return [{ json: { html } }];
